// Script Continued Below
// RJ - OU REQUEST TYPE
function onSubmit() {

	var table;
	var RequestSysId; 
	var modalForm;
	var title;
	var view;
	var ou_parent;
	var query;
	var formAction = g_form.getActionName();
	// STRY0116785 - if abbreviation changed, any other request is canceled, the prompt for confirmation will post back to
	//               save data and submit an ajax call to  update tasks
	//               The prompt modal is in the _checkAbbreviationChange() function, if it returns true, cancel the action
	// NOTE: if save is added to a form the abbreviation check might not run
	if(formAction=='save'){
		return true;
	}else{
		if(_checkAbbreviationChange()){
			return false;
		}

	}

	// STRY0088787 added if statement to check the submit is a Request submit, then doing save before continuing
	// each form acction needs to be above save confirmation below or it never gets to any other logic and stays in a confirmation loop
	if(formAction == 'request_organizational_update'  ||
		formAction == 'create_sub_ou' || 
		formAction == 'add_member_to_ou' || 
		formAction == 'add_contact_to_ou') {
		// each button needs to be added 
		if(!saveConfirmation())
			return false;

		ou_parent = g_form.getUniqueValue();

		// TESTING RETURN AFTER SAVE CONFIRMATION FOR NOW
		if(formAction == 'create_sub_ou'){
			// TODO - multilanguage - NOTE: what is done on new here should be done in Tasker Form with Tabs and other places
			open_New_Modal('x_153465_discovert_discover_office_hierarchy', getMessage('New Sub OU'), view, 'parent=' + ou_parent);
		} else if(formAction == 'add_member_to_ou'){
			// TODO - multilanguage - NOTE: what is done on new here should be done in Tasker Form with Tabs and other places
			open_New_Modal('x_153465_discovert_discover_office_members', getMessage('New OU Member'), view, 'discover_office_hierarchy=' + ou_parent);
		} else if(formAction == 'add_contact_to_ou'){
			// TODO - multilanguage - NOTE: what is done on new here should be done in Tasker Form with Tabs and other places
			open_New_Modal('x_153465_discovert_organizational_contacts', getMessage('New OU Contact'), view, 'u_contact_ou=' + ou_parent);

		} else if(formAction == 'request_organizational_update'){
			if(!g_scratchpad.OUHA_responsible.GlobalAdministrators.value && !g_scratchpad.OUHA_responsible.Administrators.value){
				// no people are available to send request, raise error
				g_form.addErrorMessage(getMessage('Tasker - There are no available Hierarchy Administrators. Please contact your Application Administrator to add Hierarchy Administrators.'));
				return false;
			}
			open_New_Modal('x_153465_discovert_tasker_requests', getMessage('Tasker - Title - Request Hierarchy Update'), 'ou_requesttop', 'u_ou_parent=' + ou_parent);


		}
		return false;
	}

	// this is called from the Open Modal callback to refresh the form
	function refreshForm() {
		g_form.save();
	}	

	function open_New_Modal(table, title, view, query) {
		if (typeof spModal != 'undefined' ) { 
			spModal.open({
				title: title,
				backdrop:'static',
				widget: 'discovertasker-formtab',
				widgetInput: {
					table: table,
					sys_id: "-1",
					view: view,
					query: query,
					// DFCT0010643
					omitHeader: 'true',
					// STRY0040294 - added isModal - added closing of open modal
					isModal: true //,
				},
				size: 'lg',
				buttons: [],
				// 2.7.2 | 2022-01-13 | mmcc | STRY0110656 - UI- Fixed Header and Button Bars on ALL Modals and lists
				footerStyle: {
					'display': 'none'
				}
			});
		} else {
			modalForm = new GlideModalForm(title, table);
			modalForm.addParm('sysparm_query',query);
			modalForm.addParm('sysparm_view', view); //Specify a form view
			modalForm.render();
			modalForm.setSysID(-1);
			modalForm.setCompletionCallback(refreshForm);
		}
	}

	// NOTE this code exists in too many places, need to understand how to move into a client script library
	function saveConfirmation(){
		var saveConfirmed = true;
		var saveMsg =  getMessage('Tasker - Modal Save Changes Message');
		if(typeof spModal != 'undefined'){
			var fMsg = '';
			var serializeChanges = g_form.serialize(true);
			if(serializeChanges.length>0){
				// start as true, if no changes it will return true, if changes confirmation will have to set back to true
				saveConfirmed = false;
				var changeFieldList = [];
				for (var field in serializeChanges) {
					changeFieldList.push(serializeChanges[field].label.trim());
				}
				fMsg = changeFieldList.join(', ');
				spModal.confirm(saveMsg + "  "+ fMsg).then(function(confirmed) {
					g_form.save();
					saveConfirmed = true;
				});
			}
		} else if (typeof spModal == 'undefined' && g_form.modified) {
			// start as true, if no changes it will return true, if changes confirmation will have to set back to true
			saveConfirmed = false;
			saveMsg += JSON.stringify(g_form.modifiedFields);
			if(confirm(saveMsg)){
				g_form.save();
				saveConfirmed = true;				
			} else{
				return saveConfirmed;
			}			
		}

		return saveConfirmed;
	}

	// STRY0116785
	// STRY0116785 - if abbreviation changed, any other request is canceled, the prompt for confirmation will post back to
	//               save data and update tasks the prompt modal is in the _checkAbbreviationChange() function, if it returns true, cancel the action	
	function _checkAbbreviationChange(){
		var abbreviationChanged = false;
		var serializeChanges;
		var field;
		var title = getMessage("Tasker - Title - Update OU Abbreviation for") + " " + g_scratchpad.office_abbreviation;		
		if(typeof spModal != 'undefined'){
			serializeChanges = g_form.serialize(true);
			if(serializeChanges.length>0){
				var changeFieldList = [];
				for (field in serializeChanges) {
					if(serializeChanges[field].name == "office_abbreviation"){
						abbreviationChanged = true;
						break;
					}
				}
				if(abbreviationChanged){
					_promptChangeTaskerNumber(title);
				}

			}
		} else if (typeof spModal == 'undefined' && g_form.modified) {
			// start as true, if no changes it will return true, if changes confirmation will have to set back to true
			serializeChanges = g_form.modifiedFields;
			var formValues = [];
			var strFormValues = "";
			var abbrChanged = false;
			for (field in serializeChanges) {
				var formValue = {};
				formValue.name = field;
				formValue.value = g_form.getValue(field);
				if(field=="x_153465_discovert_discover_office_hierarchy.office_abbreviation"){
					abbreviationChanged=true;
				}
				formValues.push(formValue);
			}
			if(abbreviationChanged){
				strFormValues = JSON.stringify(formValues);
				// STRY0119137 - STRY0119138 (corrected platform page name while working other story)
				// For Platform use UI Page named: tasker_org_abbreviation_change_prompt
				var gm = new GlideModal('x_153465_discovert_tasker_org_abbreviation_change_prompt');
				gm.setTitle(title);
				gm.setPreference('sysparm_ou_id', g_form.getUniqueValue());
				gm.setPreference('sysparm_form_values', strFormValues);
				gm.setWidth(900);
				gm.render();
			}
		}
		return abbreviationChanged;
	}
	function _promptChangeTaskerNumber(title){
		var ou_id=g_form.getUniqueValue();
		var modalSelection = {};
		spModal.open({
			title: title,
			widgetInput: {
				sys_id: ou_id
			},
			backdrop: 'static',
			widget: 'tasker_organization_abbreviation_change',
			size: 'md',
			shared: modalSelection,
			buttons: [],
			footerStyle: {
				'display': 'none'
			}
		}).then(function(response) {
			// save the ou changes
			g_form.save().then(function(){
				var ajax  = new GlideAjax('ClientTaskInfo');
				ajax.addParam('sysparm_name', 'ouAbbreviationupdateTaskerNumber');
				ajax.addParam('sysparm_ou_id',ou_id);
				// here when a primary button (Save as Draft OR Discard Changes)
				if(modalSelection.updateType == "activeTasksOnly"){
					ajax.addParam('sysparm_activeOnly', true);
					ajax.getXML(f_return_ouAbbreviationupdateTaskerNumber);
				}else if(modalSelection.updateType == "allTasks"){
					// post action to update all tasks
					ajax.addParam('sysparm_activeOnly', false);
					ajax.getXML(f_return_ouAbbreviationupdateTaskerNumber);
				}else if(modalSelection.updateType == "futureTasks"){
					// do nothing, only updating future tasks
				}
			});
		}, function() {
			// cancel selected
			// do nothing, as processing has moved on
		});
	}



	function f_return_ouAbbreviationupdateTaskerNumber(response){
		try{
			var sTasksUpdated = response.responseXML.documentElement.getAttribute("answer");
			var oTasksUpdated = JSON.parse(sTasksUpdated);
			var msgEnd = getMessage("Tasker - The number of Tasker Numbers updated in the Organizational Unit with Abbreviation [{0}]. was [{1}]").replace('{0}',oTasksUpdated.ou_abbreviation).replace('{1}',oTasksUpdated.tasksUpdated);
			g_form.addInfoMessage(msgEnd);
		}catch(e){
			jslog(e);
		}	
	}	

}
